INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('146cfaaf-aaff-451e-bc9c-ee8099f69750', $q$Cross-channel workflows$q$, $q$Build reusable multi-step notification workflows that send across email, SMS, push, chat, and in-app channels with conditional branching, delays, and batching logic.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('146cfaaf-aaff-451e-bc9c-ee8099f69750', $q$AI workflow builder$q$, $q$Generate a complete multi-channel messaging workflow from a single natural-language prompt, then refine the steps in the visual builder or in code.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('146cfaaf-aaff-451e-bc9c-ee8099f69750', $q$In-app inbox and guides$q$, $q$Drop in prebuilt frontend components for notification feeds, inboxes, and targeted in-app guides like banners, modals, and tooltips.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('146cfaaf-aaff-451e-bc9c-ee8099f69750', $q$Preference and send-window controls$q$, $q$Give end users self-serve control over which notification types and channels they receive, plus quiet-hours and digest scheduling.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('146cfaaf-aaff-451e-bc9c-ee8099f69750', $q$Data ingestion and personalization$q$, $q$Sync recipient, object, and event data from warehouses, CDPs, reverse ETL tools, or webhooks to personalize templates at send time.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('146cfaaf-aaff-451e-bc9c-ee8099f69750', $q$Developer tooling$q$, $q$Ship notifications with SDKs for eight languages, a CLI that works with AI coding assistants, environment-based version control, and CI validation.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('146cfaaf-aaff-451e-bc9c-ee8099f69750', $q$Observability and debugging$q$, $q$Trace individual message deliveries, inspect logs, and roll back workflow versions when something goes wrong in production.$q$, 6);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('146cfaaf-aaff-451e-bc9c-ee8099f69750', $q$Enterprise security and compliance$q$, $q$Meet regulatory requirements with HIPAA BAAs, SOC 2 compliance, GDPR/CCPA support, and SAML 2.0 SSO on enterprise plans.$q$, 7);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('146cfaaf-aaff-451e-bc9c-ee8099f69750', $q$Generous free tier with 10,000 messages per month and unlimited workflows and channels$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('146cfaaf-aaff-451e-bc9c-ee8099f69750', $q$Purpose-built for engineering teams, with SDKs, CLI, and version-controlled workflows$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('146cfaaf-aaff-451e-bc9c-ee8099f69750', $q$Supports a wide range of channels including email, SMS, push, chat, and Slack from one workflow$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('146cfaaf-aaff-451e-bc9c-ee8099f69750', $q$Strong observability and debugging tools for tracing individual notification deliveries$q$, 3);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('146cfaaf-aaff-451e-bc9c-ee8099f69750', $q$Backed by well-known customers such as Vercel, Webflow, and Amplitude, suggesting production reliability at scale$q$, 4);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('146cfaaf-aaff-451e-bc9c-ee8099f69750', $q$Usage-based pricing means costs can climb quickly for high-volume senders$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('146cfaaf-aaff-451e-bc9c-ee8099f69750', $q$Enterprise features like SAML SSO, i18n, and HIPAA BAAs are locked behind custom pricing$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('146cfaaf-aaff-451e-bc9c-ee8099f69750', $q$Requires engineering resources to implement; not a self-serve tool for marketers$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('146cfaaf-aaff-451e-bc9c-ee8099f69750', $q$Branding removal and email previews are gated behind the paid Starter tier$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('146cfaaf-aaff-451e-bc9c-ee8099f69750', $q$Less suited to large-scale marketing campaign management compared to dedicated marketing automation platforms$q$, 4);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('146cfaaf-aaff-451e-bc9c-ee8099f69750', $q$What is Knock used for?$q$, $q$Knock is used by engineering teams to build and manage product notifications, such as transactional emails, push alerts, SMS, in-app messages, and Slack notifications, through a single API and workflow builder instead of building delivery infrastructure from scratch.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('146cfaaf-aaff-451e-bc9c-ee8099f69750', $q$Is Knock free to use?$q$, $q$Yes, Knock has a free Developer plan that includes 10,000 messages, 500 guide active users, and 500 AI agent credits per month, with unlimited workflows and channels.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('146cfaaf-aaff-451e-bc9c-ee8099f69750', $q$Who founded Knock?$q$, $q$Knock was founded in January 2021 by Sam Seely and Chris Bell, former product and engineering leaders at Frame.io.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('146cfaaf-aaff-451e-bc9c-ee8099f69750', $q$How much does Knock cost?$q$, $q$Knock's Starter plan costs 250 dollars per month for 50,000 messages, and Enterprise pricing is custom and based on volume, with usage-based overage charges billed monthly.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('146cfaaf-aaff-451e-bc9c-ee8099f69750', $q$What is the difference between Knock and Novu?$q$, $q$Knock is a hosted, managed notification infrastructure service, while Novu is an open-source project that companies can self-host for free as an alternative, trading managed reliability for infrastructure control.$q$, 4, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('146cfaaf-aaff-451e-bc9c-ee8099f69750', $q$Does Knock support SMS and push notifications?$q$, $q$Yes, Knock supports email, SMS, push notifications, in-app messages, chat, and Slack, all orchestrated through the same workflow engine.$q$, 5, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('146cfaaf-aaff-451e-bc9c-ee8099f69750', $q$Product notification infrastructure$q$, $q$Engineering teams replace custom-built notification code with Knock's API to send transactional and lifecycle messages across channels reliably.$q$, $q$Software engineering teams at B2B SaaS companies$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('146cfaaf-aaff-451e-bc9c-ee8099f69750', $q$In-app messaging and guides$q$, $q$Teams add targeted banners, modals, and notification inboxes to their product UI using Knock's prebuilt frontend components.$q$, $q$Product teams building onboarding and engagement flows$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('146cfaaf-aaff-451e-bc9c-ee8099f69750', $q$Multi-tenant and object-based notifications$q$, $q$Companies with complex data models, like project management or collaboration tools, use Knock's custom object subscriptions to notify the right users about shared documents, projects, or threads.$q$, $q$SaaS platforms with collaborative or multi-tenant features$q$, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('146cfaaf-aaff-451e-bc9c-ee8099f69750', $q$Developer$q$, $q$Free$q$, $q$Monthly$q$, NULL, $q$["10,000 included messages per month","500 guide active users","500 AI agent credits","Unlimited notification workflows and broadcasts","Unlimited delivery channels and team members"]$q$::jsonb, 0);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('146cfaaf-aaff-451e-bc9c-ee8099f69750', $q$Starter$q$, $q$$250/month$q$, $q$Monthly$q$, NULL, $q$["50,000 included messages per month","2,500 guide active users","2,000 AI agent credits","Remove Knock branding","Email client previews"]$q$::jsonb, 1);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('146cfaaf-aaff-451e-bc9c-ee8099f69750', $q$Enterprise$q$, $q$Custom pricing$q$, $q$Annual or custom$q$, NULL, $q$["Volume-based or monthly active recipient pricing","Per-customer branding and preferences","Translation and i18n support","HIPAA compliance with signed BAA","SAML 2.0 SSO","Shared Slack channel and priority support"]$q$::jsonb, 2);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('146cfaaf-aaff-451e-bc9c-ee8099f69750', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$Knock is a notification infrastructure platform founded in 2021 by former Frame.io product and engineering leaders Sam Seely and Chris Bell. Rather than a marketing campaign tool, Knock is a developer-first API and workflow engine that sits between an application's backend and its delivery providers, handling the plumbing of sending reliable, multi-channel notifications.$q$, $q$Teams define reusable notification workflows in a visual builder or in code, covering email, SMS, push, in-app messages, chat, and Slack, with conditional logic, batching, and digesting built in. Knock is backed by Craft Ventures and Afore Capital and is used in production by companies including Vercel, Webflow, and Amplitude.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('146cfaaf-aaff-451e-bc9c-ee8099f69750', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$Knock's core is the workflow engine: multi-step, multi-channel messaging journeys with per-recipient preference checks, send-window controls, and an AI workflow builder that can draft a workflow from a single prompt. Data can be synced in from warehouses, CDPs, or webhooks to personalize templates dynamically.$q$, $q$For developers, Knock offers SDKs in eight languages, a CLI compatible with AI coding assistants, environment-based version control with rollback, and built-in observability for tracing individual message deliveries. Prebuilt frontend components add in-app notification feeds, inboxes, and targeted guides like banners and modals.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('146cfaaf-aaff-451e-bc9c-ee8099f69750', $q$pricing-overview$q$, $q$Pricing$q$, 2, ARRAY[$q$Knock uses a three-tier, usage-metered pricing model. The free Developer plan includes 10,000 messages and 500 guide active users per month with unlimited workflows and channels. The Starter plan costs 250 dollars per month for 50,000 messages and adds branding removal and email previews.$q$, $q$Enterprise pricing is custom and volume-based, unlocking translation support, HIPAA BAAs, SAML SSO, and priority support. Overage charges across all tiers are billed in arrears on the following month's invoice.$q$]::text[], 2);
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('146cfaaf-aaff-451e-bc9c-ee8099f69750', '96595ec7-e449-4fd5-803d-e73ba922c0ca') ON CONFLICT DO NOTHING;
