INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('afdb353e-eadb-46f7-a2cf-7af280948165', $q$WYSIWYG article editor with custom themes$q$, $q$Write and format articles in a visual editor, then publish to a fully branded site with custom domains and CSS/HTML theming.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('afdb353e-eadb-46f7-a2cf-7af280948165', $q$AI chatbot and AI-powered search$q$, $q$Let readers ask questions and get answers sourced directly from the knowledge base content.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('afdb353e-eadb-46f7-a2cf-7af280948165', $q$AI article creation, summaries, and style guide review$q$, $q$Draft, summarize, and check articles against a company's writing standards using built-in AI tools.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('afdb353e-eadb-46f7-a2cf-7af280948165', $q$Custom domain and full white-label branding$q$, $q$Remove KnowledgeOwl branding and publish under your own domain on the Pro tier and above.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('afdb353e-eadb-46f7-a2cf-7af280948165', $q$SAML and Salesforce SSO$q$, $q$Manage enterprise authentication for authors and readers through single sign-on integrations.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('afdb353e-eadb-46f7-a2cf-7af280948165', $q$Reader analytics and unhelpful-article reporting$q$, $q$See which articles are viewed, searched for without results, or rated unhelpful to guide content improvements.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('afdb353e-eadb-46f7-a2cf-7af280948165', $q$Developer API access$q$, $q$Programmatically manage articles and integrate the knowledge base with other systems.$q$, 6);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('afdb353e-eadb-46f7-a2cf-7af280948165', $q$White-glove migration and dedicated expert onboarding calls$q$, $q$Get hands-on help migrating existing content and recurring calls with a KnowledgeOwl expert on every paid plan.$q$, 7);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('afdb353e-eadb-46f7-a2cf-7af280948165', $q$Hands-on onboarding with recurring 1:1 expert calls on every paid plan$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('afdb353e-eadb-46f7-a2cf-7af280948165', $q$Independently owned, profitable company not chasing VC growth targets$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('afdb353e-eadb-46f7-a2cf-7af280948165', $q$Strong compliance options such as HIPAA, GDPR, and SAML SSO even on mid-tier plans$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('afdb353e-eadb-46f7-a2cf-7af280948165', $q$30-day free trial with no credit card required$q$, 3);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('afdb353e-eadb-46f7-a2cf-7af280948165', $q$Certified B Corporation appeals to values-driven organizations$q$, 4);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('afdb353e-eadb-46f7-a2cf-7af280948165', $q$No free-forever plan; paid plans start at 100 dollars per month$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('afdb353e-eadb-46f7-a2cf-7af280948165', $q$Each plan includes only one knowledge base and one author by default, with paid add-ons for more$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('afdb353e-eadb-46f7-a2cf-7af280948165', $q$More expensive than some competitors for small teams needing basic documentation$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('afdb353e-eadb-46f7-a2cf-7af280948165', $q$Article limits per tier could require upgrading as content libraries grow$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('afdb353e-eadb-46f7-a2cf-7af280948165', $q$Smaller company size than VC-backed competitors like Document360$q$, 4);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('afdb353e-eadb-46f7-a2cf-7af280948165', $q$How much does KnowledgeOwl cost?$q$, $q$KnowledgeOwl has four paid plans: Basic at 100 dollars per month, Pro at 250 dollars per month, Business at 500 dollars per month, and custom Enterprise pricing, all with a 30-day free trial.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('afdb353e-eadb-46f7-a2cf-7af280948165', $q$Does KnowledgeOwl have a free plan?$q$, $q$KnowledgeOwl does not offer a free-forever plan, but every paid tier includes a 30-day free trial with no credit card required.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('afdb353e-eadb-46f7-a2cf-7af280948165', $q$When was KnowledgeOwl founded?$q$, $q$KnowledgeOwl was founded in 2015 and is headquartered in Boulder, Colorado.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('afdb353e-eadb-46f7-a2cf-7af280948165', $q$Does KnowledgeOwl have AI features?$q$, $q$Yes, KnowledgeOwl includes an AI chatbot, AI-powered search, AI-assisted article creation and summarization, and an AI style guide reviewer on all paid plans.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('afdb353e-eadb-46f7-a2cf-7af280948165', $q$Is KnowledgeOwl good for internal wikis as well as customer help centers?$q$, $q$Yes, KnowledgeOwl is commonly used for both external customer-facing help centers and internal employee wikis or documentation.$q$, 4, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('afdb353e-eadb-46f7-a2cf-7af280948165', $q$How is KnowledgeOwl different from Confluence?$q$, $q$KnowledgeOwl is a purpose-built knowledge base publishing tool with reader analytics, branding, and AI search, while Confluence is a broader team wiki and collaboration tool often repurposed for documentation.$q$, 5, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('afdb353e-eadb-46f7-a2cf-7af280948165', $q$Customer-facing help center$q$, $q$Support teams publish a branded, searchable help center so customers can self-serve answers instead of contacting support.$q$, $q$Customer support and success teams$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('afdb353e-eadb-46f7-a2cf-7af280948165', $q$Internal employee wiki and SOPs$q$, $q$Operations and HR teams centralize internal processes, policies, and training material in a permissioned internal knowledge base.$q$, $q$Internal operations, HR, and IT teams$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('afdb353e-eadb-46f7-a2cf-7af280948165', $q$Product and technical documentation$q$, $q$Product teams maintain versioned user manuals and technical documentation with developer API access for embedding docs elsewhere.$q$, $q$Product and technical writing teams$q$, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('afdb353e-eadb-46f7-a2cf-7af280948165', $q$Basic$q$, $q$$100/month$q$, $q$Monthly$q$, NULL, $q$["1 knowledge base, 1 author","Up to 1,000 articles","Unlimited readers","Monthly 1:1 expert calls","Core AI features","45 days of analytics data"]$q$::jsonb, 0);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('afdb353e-eadb-46f7-a2cf-7af280948165', $q$Pro$q$, $q$$250/month$q$, $q$Monthly$q$, NULL, $q$["1 knowledge base, 1 author","Up to 2,500 articles","Bi-weekly 1:1 expert calls","Developer API access","Custom domain and full branding","90 days of analytics plus reader reports"]$q$::jsonb, 1);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('afdb353e-eadb-46f7-a2cf-7af280948165', $q$Business$q$, $q$$500/month$q$, $q$Monthly$q$, NULL, $q$["1 knowledge base, 1 author","Up to 5,000 articles","Weekly 1:1 expert calls","Advanced security features","Custom roles and granular permissions","450 days of analytics plus reader reports"]$q$::jsonb, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('afdb353e-eadb-46f7-a2cf-7af280948165', $q$Enterprise$q$, $q$Custom pricing$q$, $q$Annual or custom$q$, NULL, $q$["Unlimited articles and authors","Dedicated account management","Custom SLA with 99.9% uptime guarantee","Unlimited analytics data"]$q$::jsonb, 3);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('afdb353e-eadb-46f7-a2cf-7af280948165', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$KnowledgeOwl is a knowledge base platform founded in 2015 and based in Boulder, Colorado. It is a small, independently owned, profitable company (a certified B Corporation) rather than a venture-backed startup, and it focuses squarely on helping teams create, organize, and publish documentation.$q$, $q$The product covers both external use cases, like customer-facing help centers, and internal ones, like employee wikis and SOPs, with a WYSIWYG editor, customizable categories, and fully brandable, custom-domain publishing.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('afdb353e-eadb-46f7-a2cf-7af280948165', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$KnowledgeOwl has added AI throughout the product: an AI chatbot for readers, AI-powered search, AI-assisted article drafting and summarization, and an AI style-guide reviewer. Administrative tooling includes granular roles and permissions, SAML and Salesforce SSO, HIPAA and GDPR compliance agreements, and a developer API.$q$, $q$A distinguishing feature is high-touch onboarding: every paid plan includes recurring one-on-one calls with a KnowledgeOwl expert, along with white-glove migration assistance when moving from another platform.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('afdb353e-eadb-46f7-a2cf-7af280948165', $q$pricing-overview$q$, $q$Pricing$q$, 2, ARRAY[$q$KnowledgeOwl offers four tiers, each including one knowledge base and one author by default: Basic at 100 dollars/month (1,000 articles), Pro at 250 dollars/month (2,500 articles), Business at 500 dollars/month (5,000 articles), and custom-priced Enterprise with unlimited articles and a 99.9 percent uptime SLA.$q$, $q$Extra authors cost 25 dollars each and extra knowledge bases cost 50 dollars each. Every plan includes a 30-day free trial with no credit card required.$q$]::text[], 2);
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('afdb353e-eadb-46f7-a2cf-7af280948165', '610c2598-d057-4727-bf3b-e907b0daed7f') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('afdb353e-eadb-46f7-a2cf-7af280948165', '96595ec7-e449-4fd5-803d-e73ba922c0ca') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('afdb353e-eadb-46f7-a2cf-7af280948165', '4137e3dc-5b54-4d6a-adfa-85ce8104e38f') ON CONFLICT DO NOTHING;
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('96e6b159-e2df-47d3-a4b4-493bd926551e', $q$Deep Research mode$q$, $q$Generate fact-checked, cited content by pulling in live web data during the writing process.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('96e6b159-e2df-47d3-a4b4-493bd926551e', $q$Real-time SERP analysis$q$, $q$Scan top-ranking pages for a target keyword to surface entities, subtopics, and semantic keywords.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('96e6b159-e2df-47d3-a4b4-493bd926551e', $q$Automatic internal linking$q$, $q$Cross-link new articles to relevant existing pages on the same site automatically.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('96e6b159-e2df-47d3-a4b4-493bd926551e', $q$One-click publishing$q$, $q$Publish directly to WordPress, Shopify, Webflow, or Ghost with formatting preserved.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('96e6b159-e2df-47d3-a4b4-493bd926551e', $q$AI image generation$q$, $q$Create supporting images for articles without leaving the platform.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('96e6b159-e2df-47d3-a4b4-493bd926551e', $q$Bulk content creation$q$, $q$Generate many articles at once, with faster bulk-processing speeds on higher-volume plans.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('96e6b159-e2df-47d3-a4b4-493bd926551e', $q$Outline editor$q$, $q$Control article structure and headings before the full draft is generated.$q$, 6);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('96e6b159-e2df-47d3-a4b4-493bd926551e', $q$Amazon affiliate article generator$q$, $q$Produce product roundup and review content using live Amazon product data.$q$, 7);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('96e6b159-e2df-47d3-a4b4-493bd926551e', $q$Free tier with 5,000 words to test before paying$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('96e6b159-e2df-47d3-a4b4-493bd926551e', $q$Deep Research mode reduces factual errors compared to typical AI writers$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('96e6b159-e2df-47d3-a4b4-493bd926551e', $q$Granular pricing tiers scale from solo bloggers to large agencies$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('96e6b159-e2df-47d3-a4b4-493bd926551e', $q$Direct publishing integrations save time versus copy-pasting into a CMS$q$, 3);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('96e6b159-e2df-47d3-a4b4-493bd926551e', $q$Bundles writing, images, internal linking, and lead magnets in one subscription$q$, 4);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('96e6b159-e2df-47d3-a4b4-493bd926551e', $q$Word allowances are consumed twice as fast when using the most capable models$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('96e6b159-e2df-47d3-a4b4-493bd926551e', $q$Nine pricing tiers can make it confusing to pick the right plan$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('96e6b159-e2df-47d3-a4b4-493bd926551e', $q$AI-generated content still typically needs human editing for quality and accuracy$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('96e6b159-e2df-47d3-a4b4-493bd926551e', $q$Limited public information on company funding or team size$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('96e6b159-e2df-47d3-a4b4-493bd926551e', $q$Higher-volume Scale plans are priced for agencies, not casual users$q$, 4);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('96e6b159-e2df-47d3-a4b4-493bd926551e', $q$What is Koala AI used for?$q$, $q$Koala AI, through its KoalaWriter tool, is used to generate SEO-optimized blog posts and articles using SERP research, fact-checked Deep Research, and automatic internal linking, then publish them directly to platforms like WordPress or Shopify.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('96e6b159-e2df-47d3-a4b4-493bd926551e', $q$Is Koala AI free?$q$, $q$Koala AI offers a free tier with 5,000 words to try the platform, with paid plans starting at 9 dollars per month for 15,000 words.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('96e6b159-e2df-47d3-a4b4-493bd926551e', $q$Who created Koala AI?$q$, $q$Koala AI's KoalaWriter product was created by founder Connor Smith and launched in April 2023.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('96e6b159-e2df-47d3-a4b4-493bd926551e', $q$What AI models does Koala AI use?$q$, $q$Koala AI uses models from the GPT and Claude families, including GPT-5 and Claude 4, with word allowances calculated against GPT-5 Mini as the baseline.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('96e6b159-e2df-47d3-a4b4-493bd926551e', $q$Does Koala AI integrate with WordPress?$q$, $q$Yes, Koala AI supports one-click publishing to WordPress, as well as Shopify, Webflow, and Ghost.$q$, 4, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('96e6b159-e2df-47d3-a4b4-493bd926551e', $q$How is Koala AI different from Jasper or Copy.ai?$q$, $q$Koala AI focuses specifically on SEO content with built-in SERP analysis, Deep Research fact-checking, and automatic internal linking, while Jasper and Copy.ai are broader marketing copywriting tools without the same SEO-research depth.$q$, 5, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('96e6b159-e2df-47d3-a4b4-493bd926551e', $q$SEO blog content at scale$q$, $q$Bloggers and niche-site owners generate keyword-targeted articles using SERP analysis and Deep Research, then publish directly to their CMS.$q$, $q$Solo bloggers and affiliate publishers$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('96e6b159-e2df-47d3-a4b4-493bd926551e', $q$Agency content production$q$, $q$SEO agencies use Scale-tier plans to produce large volumes of client articles with bulk generation and automatic internal linking.$q$, $q$SEO and content marketing agencies$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('96e6b159-e2df-47d3-a4b4-493bd926551e', $q$Amazon affiliate content$q$, $q$Affiliate marketers generate product roundup and review articles pulling in live Amazon product data.$q$, $q$Affiliate marketers and niche-site operators$q$, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('96e6b159-e2df-47d3-a4b4-493bd926551e', $q$Free$q$, $q$$0$q$, $q$Monthly$q$, NULL, $q$["5,000 words to try the platform"]$q$::jsonb, 0);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('96e6b159-e2df-47d3-a4b4-493bd926551e', $q$Essentials$q$, $q$$9/month$q$, $q$Monthly$q$, NULL, $q$["15,000 words/month","250 chat messages","GPT-5 and Claude 4 access","AI images","WordPress integration"]$q$::jsonb, 1);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('96e6b159-e2df-47d3-a4b4-493bd926551e', $q$Professional$q$, $q$$49/month$q$, $q$Monthly$q$, NULL, $q$["100,000 words/month","1,000 messages","Unlimited uploads","Automatic internal linking","Deep Research"]$q$::jsonb, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('96e6b159-e2df-47d3-a4b4-493bd926551e', $q$Boost$q$, $q$$99/month$q$, $q$Monthly$q$, NULL, $q$["250,000 words/month","2,500 messages","2x faster bulk creation"]$q$::jsonb, 3);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('96e6b159-e2df-47d3-a4b4-493bd926551e', $q$Growth$q$, $q$$179/month$q$, $q$Monthly$q$, NULL, $q$["500,000 words/month","5,000 messages"]$q$::jsonb, 4);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('96e6b159-e2df-47d3-a4b4-493bd926551e', $q$Elite$q$, $q$$350/month$q$, $q$Monthly$q$, NULL, $q$["1,000,000 words/month","10,000 messages"]$q$::jsonb, 5);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('96e6b159-e2df-47d3-a4b4-493bd926551e', $q$Advanced$q$, $q$$500/month$q$, $q$Monthly$q$, NULL, $q$["1,500,000 words/month","12,500 messages"]$q$::jsonb, 6);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('96e6b159-e2df-47d3-a4b4-493bd926551e', $q$Scale I$q$, $q$$750/month$q$, $q$Monthly$q$, NULL, $q$["2,500,000 words/month","15,000 messages","3x faster bulk creation"]$q$::jsonb, 7);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('96e6b159-e2df-47d3-a4b4-493bd926551e', $q$Scale II$q$, $q$$1,250/month$q$, $q$Monthly$q$, NULL, $q$["5,000,000 words/month","20,000 messages"]$q$::jsonb, 8);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('96e6b159-e2df-47d3-a4b4-493bd926551e', $q$Scale III$q$, $q$$2,000/month$q$, $q$Monthly$q$, NULL, $q$["10,000,000 words/month","25,000 messages"]$q$::jsonb, 9);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('96e6b159-e2df-47d3-a4b4-493bd926551e', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$Koala AI, at koala.sh, is an AI writing platform focused specifically on search-optimized content. Launched in April 2023 by founder Connor Smith and based in Gainesville, Florida, it bundles five tools, KoalaWriter, KoalaChat, KoalaImages, KoalaLinks, and KoalaMagnets, under one subscription.$q$, $q$The platform reports over 19,000 users, ranging from solo bloggers to SEO agencies, and centers on generating publish-ready articles using GPT-5 and Claude 4 family models combined with live SERP research.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('96e6b159-e2df-47d3-a4b4-493bd926551e', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$Koala AI's Deep Research mode pulls in live web data and citations to reduce hallucinated facts, while real-time SERP analysis surfaces the entities and semantic keywords needed to compete for a target keyword. Articles can include automatic schema markup, AI-generated images, and automatic internal linking.$q$, $q$Content publishes directly to WordPress, Shopify, Webflow, or Ghost with formatting preserved. Other tools include an outline editor, a readability-focused Polish pass, bulk content generation, and an Amazon affiliate article workflow using live product data.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('96e6b159-e2df-47d3-a4b4-493bd926551e', $q$pricing-overview$q$, $q$Pricing$q$, 2, ARRAY[$q$Koala AI offers a free tier with 5,000 words, then nine paid tiers from Essentials at 9 dollars per month (15,000 words) up to Scale III at 2,000 dollars per month (10,000,000 words), billed monthly or annually with a 20 percent annual discount.$q$, $q$Word allowances are calculated against GPT-5 Mini as the baseline; generating with the more capable GPT-5.2 or Claude 4.5 consumes words at twice the rate, and higher tiers unlock faster bulk content generation.$q$]::text[], 2);
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('96e6b159-e2df-47d3-a4b4-493bd926551e', 'c296bd6a-c865-41d7-8807-5dce653dd3f5') ON CONFLICT DO NOTHING;
