INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('f15ae2d8-b82f-4e7b-b033-07c65a5c2617', $q$Skinnable, fully customizable interface$q$, $q$Change themes and layouts through the add-on repository to personalize the entire experience.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('f15ae2d8-b82f-4e7b-b033-07c65a5c2617', $q$Extensive add-on ecosystem$q$, $q$Install video and audio plugins, PVR backends, and skins to extend functionality well beyond the base app.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('f15ae2d8-b82f-4e7b-b033-07c65a5c2617', $q$Broad format and codec support$q$, $q$Play a wide range of video and audio containers and codecs from local and network storage.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('f15ae2d8-b82f-4e7b-b033-07c65a5c2617', $q$Live TV and DVR$q$, $q$Watch and record live television through PVR add-ons connected to tuner hardware or IPTV sources.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('f15ae2d8-b82f-4e7b-b033-07c65a5c2617', $q$Cross-platform availability$q$, $q$Run Kodi on Windows, macOS, Linux, Android, iOS, tvOS, and BSD.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('f15ae2d8-b82f-4e7b-b033-07c65a5c2617', $q$Metadata scraping$q$, $q$Automatically fetch posters, fan art, cast info, and plot summaries for movie, TV, and music libraries.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('f15ae2d8-b82f-4e7b-b033-07c65a5c2617', $q$Multi-device library sync$q$, $q$Share a single media library across multiple Kodi installations using a central MySQL or MariaDB database.$q$, 6);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('f15ae2d8-b82f-4e7b-b033-07c65a5c2617', $q$Remote control options$q$, $q$Control playback via the on-device interface, a built-in web interface, or companion remote apps.$q$, 7);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('f15ae2d8-b82f-4e7b-b033-07c65a5c2617', $q$Completely free with no ads, subscriptions, or licensing fees$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('f15ae2d8-b82f-4e7b-b033-07c65a5c2617', $q$Fully open source under the GPL, auditable and modifiable$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('f15ae2d8-b82f-4e7b-b033-07c65a5c2617', $q$Massive add-on ecosystem for deep customization$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('f15ae2d8-b82f-4e7b-b033-07c65a5c2617', $q$Runs on almost any hardware and OS, including Raspberry Pi$q$, 3);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('f15ae2d8-b82f-4e7b-b033-07c65a5c2617', $q$No dependency on a company staying in business$q$, 4);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('f15ae2d8-b82f-4e7b-b033-07c65a5c2617', $q$Steeper learning curve than consumer apps like Plex$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('f15ae2d8-b82f-4e7b-b033-07c65a5c2617', $q$No official remote-streaming or cloud access without third-party add-ons$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('f15ae2d8-b82f-4e7b-b033-07c65a5c2617', $q$Relies on volunteer community support rather than dedicated customer service$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('f15ae2d8-b82f-4e7b-b033-07c65a5c2617', $q$Some third-party add-ons raise legal and security concerns$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('f15ae2d8-b82f-4e7b-b033-07c65a5c2617', $q$Interface and setup can feel dated compared to modern streaming apps$q$, 4);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('f15ae2d8-b82f-4e7b-b033-07c65a5c2617', $q$Is Kodi free to use?$q$, $q$Yes, Kodi is completely free and open source, with no subscription fees, distributed under the GPL version 2 or later license.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('f15ae2d8-b82f-4e7b-b033-07c65a5c2617', $q$Who develops Kodi?$q$, $q$Kodi is developed by a global community of volunteer contributors and governed by the XBMC Foundation, a non-profit established in 2009.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('f15ae2d8-b82f-4e7b-b033-07c65a5c2617', $q$What was Kodi called before?$q$, $q$Kodi was originally released in 2004 as Xbox Media Center, or XBMC, before being renamed Kodi in July 2014.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('f15ae2d8-b82f-4e7b-b033-07c65a5c2617', $q$Is Kodi legal?$q$, $q$Kodi itself is fully legal open-source software; legal risk comes only from unofficial third-party add-ons that stream copyrighted content without authorization.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('f15ae2d8-b82f-4e7b-b033-07c65a5c2617', $q$What devices does Kodi run on?$q$, $q$Kodi runs on Windows, macOS, Linux, Android, iOS, tvOS, and BSD, and is commonly installed on Raspberry Pi and dedicated home theater PC hardware.$q$, 4, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('f15ae2d8-b82f-4e7b-b033-07c65a5c2617', $q$How is Kodi different from Plex?$q$, $q$Kodi is a standalone, local media player app you install directly on your playback device, while Plex uses a client-server model with a central media server and offers commercial premium features like remote streaming.$q$, 5, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('f15ae2d8-b82f-4e7b-b033-07c65a5c2617', $q$Home theater PC media center$q$, $q$Enthusiasts build dedicated HTPCs or Raspberry Pi boxes running Kodi to organize and play their personal movie, TV, and music collections on a big screen.$q$, $q$Home theater and HTPC enthusiasts$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('f15ae2d8-b82f-4e7b-b033-07c65a5c2617', $q$Cord-cutter live TV and DVR$q$, $q$Users add PVR add-ons to Kodi to watch and record live TV from tuner hardware or IPTV sources.$q$, $q$Cord-cutters replacing cable TV$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('f15ae2d8-b82f-4e7b-b033-07c65a5c2617', $q$Custom streaming device builds$q$, $q$Hobbyists install Kodi-based distributions like LibreELEC or OSMC on small-form-factor devices to create dedicated streaming appliances.$q$, $q$DIY and open-source hardware hobbyists$q$, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('f15ae2d8-b82f-4e7b-b033-07c65a5c2617', $q$Kodi$q$, $q$Free$q$, $q$N/A$q$, NULL, $q$["Fully open-source media center software","No subscription or licensing fees","Community-developed add-ons and skins","Available on all major desktop and mobile platforms"]$q$::jsonb, 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('f15ae2d8-b82f-4e7b-b033-07c65a5c2617', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$Kodi is a free, open-source media center application with origins going back to 2002 as Xbox Media Player, later renamed XBMC in 2004 and then Kodi in July 2014. It is developed by a global volunteer community and governed by the non-profit XBMC Foundation, established in 2009.$q$, $q$The software organizes and plays local and network video, music, photos, podcasts, and live TV, and runs on Windows, macOS, Linux, Android, iOS, tvOS, and BSD, making it a favorite for home theater PCs and DIY streaming boxes.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('f15ae2d8-b82f-4e7b-b033-07c65a5c2617', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$Kodi supports an extensive range of audio and video formats, scrapes rich metadata for movie and TV libraries, and can sync a shared library across devices via a central MySQL or MariaDB database. Live TV and DVR functionality is available through PVR add-ons.$q$, $q$Its skinnable interface and large add-on repository let users heavily customize the experience, from new themes to streaming plugins and remote-control apps, and it is commonly paired with dedicated distributions like LibreELEC and OSMC on Raspberry Pi hardware.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('f15ae2d8-b82f-4e7b-b033-07c65a5c2617', $q$pricing-overview$q$, $q$Pricing$q$, 2, ARRAY[$q$Kodi is completely free with no subscription, license fee, or paid tier of any kind. It is funded through donations to the XBMC Foundation rather than commercial revenue.$q$, $q$Because there is no company selling the software, Kodi's continued availability does not depend on a business remaining profitable, distinguishing it from freemium alternatives like Plex and Emby that gate certain features behind paid plans.$q$]::text[], 2);
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('f15ae2d8-b82f-4e7b-b033-07c65a5c2617', '97eb8f3e-e378-4a5d-b2a5-331706e86e50') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('f15ae2d8-b82f-4e7b-b033-07c65a5c2617', 'efe7ced3-7cfa-4b39-9792-3427d24fa58d') ON CONFLICT DO NOTHING;
