INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('237520e2-d5af-4e71-b585-63b5af2e41f1', $q$Self-hosted, private music library$q$, $q$Run Koel on your own server or NAS to stream your personal collection without a third-party service.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('237520e2-d5af-4e71-b585-63b5af2e41f1', $q$Subsonic and OpenSubsonic API support$q$, $q$Connect any existing Subsonic-compatible client app to a Koel server.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('237520e2-d5af-4e71-b585-63b5af2e41f1', $q$Cross-device playback sync$q$, $q$Pick up playback where you left off across different devices.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('237520e2-d5af-4e71-b585-63b5af2e41f1', $q$Smart playlists and favorites$q$, $q$Build dynamic playlists based on saved criteria and mark favorite tracks.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('237520e2-d5af-4e71-b585-63b5af2e41f1', $q$Native Koel Player mobile apps$q$, $q$Use dedicated iOS and Android apps built specifically for Koel.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('237520e2-d5af-4e71-b585-63b5af2e41f1', $q$Equalizer and visualizers$q$, $q$Fine-tune audio output and enjoy visual effects during playback.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('237520e2-d5af-4e71-b585-63b5af2e41f1', $q$Radio and podcast support$q$, $q$Listen to radio stations and podcasts alongside your personal music library.$q$, 6);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('237520e2-d5af-4e71-b585-63b5af2e41f1', $q$Metadata enrichment$q$, $q$Pull additional artist and track information from MusicBrainz, Last.fm, Spotify, and YouTube.$q$, 7);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('237520e2-d5af-4e71-b585-63b5af2e41f1', $q$Community edition is free forever with no artificial limits$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('237520e2-d5af-4e71-b585-63b5af2e41f1', $q$Fully open source and self-hosted, giving complete data ownership$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('237520e2-d5af-4e71-b585-63b5af2e41f1', $q$Subsonic API compatibility unlocks a large ecosystem of existing mobile clients$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('237520e2-d5af-4e71-b585-63b5af2e41f1', $q$Koel Plus is a one-time purchase, not a subscription$q$, 3);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('237520e2-d5af-4e71-b585-63b5af2e41f1', $q$Modern, fast interface built with Vue.js$q$, 4);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('237520e2-d5af-4e71-b585-63b5af2e41f1', $q$Requires self-hosting knowledge (server, PHP, database, Docker)$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('237520e2-d5af-4e71-b585-63b5af2e41f1', $q$No official cloud-hosted version for non-technical users$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('237520e2-d5af-4e71-b585-63b5af2e41f1', $q$Multi-user and cloud storage features are locked behind the paid Plus tier$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('237520e2-d5af-4e71-b585-63b5af2e41f1', $q$Smaller community and ecosystem than Plex or Jellyfin$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('237520e2-d5af-4e71-b585-63b5af2e41f1', $q$Relies on a single primary maintainer, a common open-source project risk$q$, 4);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('237520e2-d5af-4e71-b585-63b5af2e41f1', $q$Is Koel free?$q$, $q$Yes, the Koel Community edition is free and open source. Koel Plus, a one-time paid upgrade starting at 19.99 euros, adds premium features like cloud storage and multi-library support.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('237520e2-d5af-4e71-b585-63b5af2e41f1', $q$Who created Koel?$q$, $q$Koel was created by developer Phan An and has been in active development since 2015.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('237520e2-d5af-4e71-b585-63b5af2e41f1', $q$Does Koel work with mobile apps?$q$, $q$Yes, Koel speaks the Subsonic and OpenSubsonic APIs, so it works with many existing Subsonic-compatible mobile apps, and also has its own native Koel Player app.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('237520e2-d5af-4e71-b585-63b5af2e41f1', $q$What technology is Koel built with?$q$, $q$Koel is built with a Laravel (PHP) backend and a Vue.js frontend.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('237520e2-d5af-4e71-b585-63b5af2e41f1', $q$Can Koel stream lossless audio?$q$, $q$Yes, Koel supports transparent lossless audio streaming.$q$, 4, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('237520e2-d5af-4e71-b585-63b5af2e41f1', $q$How is Koel different from Navidrome?$q$, $q$Koel and Navidrome are both free, open-source, self-hosted Subsonic-compatible music servers; Koel is built on PHP/Laravel with a one-time-purchase premium tier, while Navidrome is written in Go and remains entirely free.$q$, 5, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('237520e2-d5af-4e71-b585-63b5af2e41f1', $q$Personal music streaming server$q$, $q$Users with large local music collections self-host Koel to stream their library from any device, similar to a private Spotify.$q$, $q$Home server enthusiasts and music collectors$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('237520e2-d5af-4e71-b585-63b5af2e41f1', $q$Family or shared household streaming$q$, $q$With Koel Plus, households set up individual user libraries so multiple family members can manage separate music collections on one server.$q$, $q$Households sharing a home media server$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('237520e2-d5af-4e71-b585-63b5af2e41f1', $q$Mobile playback via Subsonic clients$q$, $q$Users connect existing Subsonic-compatible mobile apps to their self-hosted Koel server for offline-capable mobile listening.$q$, $q$Mobile listeners using Subsonic-ecosystem apps$q$, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('237520e2-d5af-4e71-b585-63b5af2e41f1', $q$Community$q$, $q$Free$q$, $q$N/A$q$, NULL, $q$["Open-source, self-hosted music server","Transparent lossless streaming","Smart playlists and favorites","Subsonic and OpenSubsonic API support","Radio and podcast support"]$q$::jsonb, 0);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('237520e2-d5af-4e71-b585-63b5af2e41f1', $q$Koel Plus$q$, $q$From EUR 19.99 (pay what you want)$q$, $q$One-time purchase$q$, NULL, $q$["Cloud storage driver support","Individual per-user libraries","Collaboration and sharing tools","Single sign-on support","No recurring payments"]$q$::jsonb, 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('237520e2-d5af-4e71-b585-63b5af2e41f1', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$Koel is a self-hosted, open-source personal music streaming server created by developer Phan An and in active development since 2015. Built with Laravel on the backend and Vue.js on the frontend, it lets users stream their own music library through a private, Spotify-like web app running on their own server.$q$, $q$The Community edition is free forever, while an optional Koel Plus upgrade adds features for more advanced or shared setups. Koel is aimed at self-hosters and homelab users who want full ownership of their music rather than a subscription streaming service.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('237520e2-d5af-4e71-b585-63b5af2e41f1', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$Koel supports transparent lossless streaming, cross-device playback sync, smart playlists, an equalizer, visualizers, and radio and podcast playback. It speaks the Subsonic and OpenSubsonic APIs, so any existing Subsonic-compatible client can connect, alongside Koel's own native Koel Player apps for iOS and Android.$q$, $q$Metadata is enriched through integrations with MusicBrainz, Wikipedia, Last.fm, Spotify, and YouTube, and the interface offers multiple themes while staying fast even on large libraries.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('237520e2-d5af-4e71-b585-63b5af2e41f1', $q$pricing-overview$q$, $q$Pricing$q$, 2, ARRAY[$q$The Koel Community edition is free and open source with no artificial limits. Koel Plus is a one-time, pay-what-you-want purchase starting at 19.99 euros rather than a subscription.$q$, $q$Koel Plus unlocks cloud storage drivers, individual per-user libraries, collaboration and sharing tools, and single sign-on, features aimed at multi-user households or more advanced self-hosted deployments.$q$]::text[], 2);
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('237520e2-d5af-4e71-b585-63b5af2e41f1', 'efe7ced3-7cfa-4b39-9792-3427d24fa58d') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('237520e2-d5af-4e71-b585-63b5af2e41f1', '97eb8f3e-e378-4a5d-b2a5-331706e86e50') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('237520e2-d5af-4e71-b585-63b5af2e41f1', '326f20ae-646d-484a-96b8-335f75262ea9') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('237520e2-d5af-4e71-b585-63b5af2e41f1', '4137e3dc-5b54-4d6a-adfa-85ce8104e38f') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('237520e2-d5af-4e71-b585-63b5af2e41f1', '7336153f-a26b-491c-b927-faf4f5a8d103') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('237520e2-d5af-4e71-b585-63b5af2e41f1', '5e4d4807-cae2-410c-9e7a-df0798a917cb') ON CONFLICT DO NOTHING;
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('6642f7be-b54a-4974-8b1c-50cd8c2c2785', $q$MARC21 and UNIMARC cataloging$q$, $q$Catalog library materials using established international bibliographic standards.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('6642f7be-b54a-4974-8b1c-50cd8c2c2785', $q$Circulation management$q$, $q$Handle checkouts, holds, renewals, and fines for patrons across one or multiple branches.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('6642f7be-b54a-4974-8b1c-50cd8c2c2785', $q$Patron and member management$q$, $q$Maintain patron accounts, borrowing history, and permissions.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('6642f7be-b54a-4974-8b1c-50cd8c2c2785', $q$Public OPAC for patron self-service$q$, $q$Let patrons search the catalog, place holds, and manage their own accounts online.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('6642f7be-b54a-4974-8b1c-50cd8c2c2785', $q$Acquisitions and serials management$q$, $q$Order and track new materials and periodical subscriptions.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('6642f7be-b54a-4974-8b1c-50cd8c2c2785', $q$Multi-branch and consortium support$q$, $q$Share a single Koha installation across multiple library branches or a regional consortium.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('6642f7be-b54a-4974-8b1c-50cd8c2c2785', $q$Responsive web design$q$, $q$Access staff and patron interfaces from desktop and mobile devices.$q$, 6);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('6642f7be-b54a-4974-8b1c-50cd8c2c2785', $q$Community-driven development$q$, $q$Benefit from continuous improvements contributed by libraries, volunteers, and commercial support vendors worldwide, with no licensing fees.$q$, 7);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('6642f7be-b54a-4974-8b1c-50cd8c2c2785', $q$Completely free and open source with no per-seat licensing costs$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('6642f7be-b54a-4974-8b1c-50cd8c2c2785', $q$Most widely adopted open-source ILS, used by thousands of libraries globally$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('6642f7be-b54a-4974-8b1c-50cd8c2c2785', $q$Full data ownership with no vendor lock-in$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('6642f7be-b54a-4974-8b1c-50cd8c2c2785', $q$Mature project with over two decades of continuous development$q$, 3);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('6642f7be-b54a-4974-8b1c-50cd8c2c2785', $q$Multiple competing commercial support vendors to choose from$q$, 4);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('6642f7be-b54a-4974-8b1c-50cd8c2c2785', $q$Requires technical staff or a paid support vendor to self-host and maintain$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('6642f7be-b54a-4974-8b1c-50cd8c2c2785', $q$Interface can feel dated compared to some modern proprietary systems$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('6642f7be-b54a-4974-8b1c-50cd8c2c2785', $q$Community support relies on mailing lists and forums rather than guaranteed SLAs$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('6642f7be-b54a-4974-8b1c-50cd8c2c2785', $q$Customization and migration typically require Perl and MARC expertise$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('6642f7be-b54a-4974-8b1c-50cd8c2c2785', $q$Support and hosting costs vary widely by vendor, making budgeting less predictable than fixed licensing$q$, 4);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('6642f7be-b54a-4974-8b1c-50cd8c2c2785', $q$Is Koha free?$q$, $q$Yes, Koha is free and open-source software with no licensing fees; libraries only pay if they choose a commercial vendor for hosting, migration, or support.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('6642f7be-b54a-4974-8b1c-50cd8c2c2785', $q$Who created Koha?$q$, $q$Koha was created in 1999 by Katipo Communications for the Horowhenua Library Trust in New Zealand, with the first installation going live in January 2000.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('6642f7be-b54a-4974-8b1c-50cd8c2c2785', $q$What does Koha mean?$q$, $q$Koha means gift or donation in the Maori language, reflecting the decision to release the software as open source.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('6642f7be-b54a-4974-8b1c-50cd8c2c2785', $q$How many libraries use Koha?$q$, $q$More than 4,700 libraries across over 6,600 facilities in over 100 countries run Koha.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('6642f7be-b54a-4974-8b1c-50cd8c2c2785', $q$Who provides support for Koha?$q$, $q$Since Koha is community-developed, support and hosting are offered by third-party companies such as ByWater Solutions, PTFS Europe, and BibLibre, rather than by a single vendor.$q$, 4, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('6642f7be-b54a-4974-8b1c-50cd8c2c2785', $q$How does Koha compare to Evergreen?$q$, $q$Both are free, open-source library systems; Koha dates back to 1999 and has broader overall adoption, while Evergreen originated in 2006 and is especially popular with large library consortia.$q$, 5, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('6642f7be-b54a-4974-8b1c-50cd8c2c2785', $q$Public library cataloging and circulation$q$, $q$Public libraries replace costly proprietary ILS platforms with Koha to manage cataloging, checkouts, holds, and patron accounts at no licensing cost.$q$, $q$Public libraries and library consortia$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('6642f7be-b54a-4974-8b1c-50cd8c2c2785', $q$School and academic library management$q$, $q$Schools and universities deploy Koha, often via a support vendor, to manage collections and give students a searchable OPAC.$q$, $q$School and academic libraries$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('6642f7be-b54a-4974-8b1c-50cd8c2c2785', $q$Multi-branch consortium sharing$q$, $q$Groups of libraries share a single Koha installation to pool cataloging effort and let patrons borrow across branches.$q$, $q$Library consortia and regional library networks$q$, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('6642f7be-b54a-4974-8b1c-50cd8c2c2785', $q$Koha (self-hosted)$q$, $q$Free$q$, $q$N/A$q$, NULL, $q$["Full ILS functionality: cataloging, circulation, acquisitions, OPAC","No licensing fees","Community support via mailing lists and wiki","Requires self-hosting infrastructure"]$q$::jsonb, 0);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('6642f7be-b54a-4974-8b1c-50cd8c2c2785', $q$Managed hosting and support$q$, $q$Varies by vendor$q$, $q$Annual or custom$q$, NULL, $q$["Hosting and server management","Migration assistance","Dedicated technical support","Custom development"]$q$::jsonb, 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('6642f7be-b54a-4974-8b1c-50cd8c2c2785', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$Koha is a free, open-source integrated library system created in 1999 by Katipo Communications for the Horowhenua Library Trust in New Zealand, with its first live installation going into production in January 2000. Widely credited as the first open-source ILS in the world, its name means gift in Maori, reflecting the decision to release it as open source.$q$, $q$Today Koha is used by more than 4,700 libraries across over 6,600 facilities in more than 100 countries, spanning public, academic, school, and special libraries, governed by a global volunteer community and released under the GPL.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('6642f7be-b54a-4974-8b1c-50cd8c2c2785', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$Koha covers the core operational needs of a library: MARC21 and UNIMARC cataloging, circulation management for checkouts, holds and fines, acquisitions and serials management, and patron account administration, all through a responsive web interface.$q$, $q$A public-facing OPAC lets patrons search the collection, place holds, and manage their own accounts. Multi-branch and consortium support lets groups of libraries share a single installation and let patrons borrow across branches.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('6642f7be-b54a-4974-8b1c-50cd8c2c2785', $q$pricing-overview$q$, $q$Pricing$q$, 2, ARRAY[$q$Koha carries no licensing fee since it is fully open source, so libraries can self-host it on their own infrastructure for free, requiring in-house technical staff with Perl and MARC expertise.$q$, $q$Alternatively, libraries can contract independent commercial vendors such as ByWater Solutions, PTFS Europe, or BibLibre for managed hosting, migration, and support, with pricing set individually by each vendor rather than by the Koha project itself.$q$]::text[], 2);
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('6642f7be-b54a-4974-8b1c-50cd8c2c2785', '97eb8f3e-e378-4a5d-b2a5-331706e86e50') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('6642f7be-b54a-4974-8b1c-50cd8c2c2785', 'efe7ced3-7cfa-4b39-9792-3427d24fa58d') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('6642f7be-b54a-4974-8b1c-50cd8c2c2785', '4137e3dc-5b54-4d6a-adfa-85ce8104e38f') ON CONFLICT DO NOTHING;
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('c742a777-74f7-4981-aabd-5b21669059f3', $q$Unlimited collections and nested sub-collections$q$, $q$Organize any number of collections and sub-collections, from books to stamps to trading cards.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('c742a777-74f7-4981-aabd-5b21669059f3', $q$Custom item metadata fields$q$, $q$Add text, number, image, and choice-list fields to describe each item in detail.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('c742a777-74f7-4981-aabd-5b21669059f3', $q$Cross-collection tagging$q$, $q$Group related items together with tags regardless of which collection they belong to.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('c742a777-74f7-4981-aabd-5b21669059f3', $q$Wishlists and loan tracking$q$, $q$Track desired items and mark items as loaned out or missing using the signs system.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('c742a777-74f7-4981-aabd-5b21669059f3', $q$Multi-user accounts with private libraries$q$, $q$Give multiple users independent, private collections on the same self-hosted instance.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('c742a777-74f7-4981-aabd-5b21669059f3', $q$Public or private sharing links$q$, $q$Share specific collections publicly or with specific people through shareable links.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('c742a777-74f7-4981-aabd-5b21669059f3', $q$Progressive Web App support$q$, $q$Install Koillection on a phone or tablet home screen for a native-app-like experience.$q$, 6);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('c742a777-74f7-4981-aabd-5b21669059f3', $q$REST API access$q$, $q$Build custom scrapers and integrations against Koillection's full REST API.$q$, 7);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('c742a777-74f7-4981-aabd-5b21669059f3', $q$Completely free and open source with no subscription$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('c742a777-74f7-4981-aabd-5b21669059f3', $q$Full data ownership through self-hosting$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('c742a777-74f7-4981-aabd-5b21669059f3', $q$Works for literally any type of collection, not just one category$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('c742a777-74f7-4981-aabd-5b21669059f3', $q$Progressive Web App support gives a native-app-like mobile experience$q$, 3);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('c742a777-74f7-4981-aabd-5b21669059f3', $q$REST API allows custom scrapers and integrations$q$, 4);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('c742a777-74f7-4981-aabd-5b21669059f3', $q$Requires self-hosting skills such as Docker, PHP, and database setup$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('c742a777-74f7-4981-aabd-5b21669059f3', $q$No built-in metadata lookups like ISBN or barcode scanning$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('c742a777-74f7-4981-aabd-5b21669059f3', $q$No official hosted cloud version for non-technical users$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('c742a777-74f7-4981-aabd-5b21669059f3', $q$Smaller community than mainstream self-hosted apps$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('c742a777-74f7-4981-aabd-5b21669059f3', $q$Relies on a single primary maintainer for long-term development$q$, 4);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('c742a777-74f7-4981-aabd-5b21669059f3', $q$Is Koillection free?$q$, $q$Yes, Koillection is completely free and open source under the MIT license, with no paid tiers or subscriptions.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('c742a777-74f7-4981-aabd-5b21669059f3', $q$Do I need to self-host Koillection?$q$, $q$Yes, Koillection is a self-hosted application; there is no official hosted cloud version, so you run it on your own server, NAS, or VPS, typically via Docker.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('c742a777-74f7-4981-aabd-5b21669059f3', $q$What can I catalog with Koillection?$q$, $q$Koillection is designed to catalog any kind of physical collection, including books, stamps, coins, vinyl records, trading cards, and action figures.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('c742a777-74f7-4981-aabd-5b21669059f3', $q$What technology does Koillection use?$q$, $q$Koillection is built with the Symfony PHP framework and API Platform on the backend and Vue.js on the frontend, and supports MySQL, MariaDB, or PostgreSQL.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('c742a777-74f7-4981-aabd-5b21669059f3', $q$Does Koillection have a mobile app?$q$, $q$Koillection is a Progressive Web App, so it can be installed on phones and tablets and used like a native app without a separate app-store download.$q$, 4, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('c742a777-74f7-4981-aabd-5b21669059f3', $q$Can I share my collection with others using Koillection?$q$, $q$Yes, Koillection supports public and private sharing links so you can expose specific collections to other people.$q$, 5, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('c742a777-74f7-4981-aabd-5b21669059f3', $q$Hobbyist collection cataloging$q$, $q$Collectors of stamps, coins, comics, or toys self-host Koillection to track their full inventory with photos and custom metadata.$q$, $q$Hobbyist collectors$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('c742a777-74f7-4981-aabd-5b21669059f3', $q$Home library and media inventory$q$, $q$Book and media owners use Koillection to catalog their physical libraries and track loans to friends and family.$q$, $q$Home librarians and media owners$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('c742a777-74f7-4981-aabd-5b21669059f3', $q$Homelab self-hosted inventory app$q$, $q$Self-hosting enthusiasts add Koillection to their Docker-based home server stack alongside other privacy-focused apps.$q$, $q$Homelab and self-hosting enthusiasts$q$, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('c742a777-74f7-4981-aabd-5b21669059f3', $q$Koillection$q$, $q$Free$q$, $q$N/A$q$, NULL, $q$["Self-hosted, open-source collection manager","Unlimited collections and items","Multi-user support","REST API access","Progressive Web App"]$q$::jsonb, 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('c742a777-74f7-4981-aabd-5b21669059f3', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$Koillection is a free, self-hosted web app for cataloging personal collections, created by developer Benjamin Jonard, with its GitHub repository dating to May 2018 and released under the MIT license. It works like a nested file system: users create collections, such as books, stamps, or trading cards, then add items inside them with custom metadata.$q$, $q$Built with Symfony and API Platform on the backend and Vue.js on the frontend, Koillection is also a Progressive Web App, letting it be installed on phones and tablets like a native app while running entirely on infrastructure the user controls.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('c742a777-74f7-4981-aabd-5b21669059f3', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$Koillection supports unlimited collections and nested sub-collections, rich custom item fields, cross-collection tagging, wishlists, and a loan or missing-item tracking system called signs. Multi-user accounts let several people maintain independent private collections on one instance.$q$, $q$Sharing controls let users expose specific collections publicly or privately via shareable links, and a full REST API supports custom integrations and scrapers, since Koillection deliberately ships without built-in metadata lookups like ISBN or barcode databases.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('c742a777-74f7-4981-aabd-5b21669059f3', $q$pricing-overview$q$, $q$Pricing$q$, 2, ARRAY[$q$Koillection is completely free and open source, with no subscription, paid tier, or hosted SaaS offering from the project itself.$q$, $q$Users self-host the application via Docker on their own server, NAS, or VPS, requiring a PHP environment and a MySQL, MariaDB, or PostgreSQL database, with all costs limited to the user's own hosting infrastructure.$q$]::text[], 2);
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('c742a777-74f7-4981-aabd-5b21669059f3', '97eb8f3e-e378-4a5d-b2a5-331706e86e50') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('c742a777-74f7-4981-aabd-5b21669059f3', 'efe7ced3-7cfa-4b39-9792-3427d24fa58d') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('c742a777-74f7-4981-aabd-5b21669059f3', '4137e3dc-5b54-4d6a-adfa-85ce8104e38f') ON CONFLICT DO NOTHING;
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('45a5beb8-a950-4bc0-908e-c7d7b3bef34a', $q$CBZ, CBR, PDF, and EPUB support$q$, $q$Organize and read comics, manga, and eBooks across multiple common file formats in one library.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('45a5beb8-a950-4bc0-908e-c7d7b3bef34a', $q$Built-in responsive web reader$q$, $q$Read directly in the browser on desktop, tablet, or phone without installing any additional software.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('45a5beb8-a950-4bc0-908e-c7d7b3bef34a', $q$OPDS and OPDS-PS syndication support$q$, $q$Connect any OPDS-compatible e-reader app to browse and download from your Komga library.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('45a5beb8-a950-4bc0-908e-c7d7b3bef34a', $q$Kobo Sync and KOReader Sync$q$, $q$Sync new books and reading progress directly to Kobo e-readers and the KOReader app.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('45a5beb8-a950-4bc0-908e-c7d7b3bef34a', $q$Multi-user access with content restrictions$q$, $q$Set per-library permissions, age restrictions, and content labels for shared household use.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('45a5beb8-a950-4bc0-908e-c7d7b3bef34a', $q$REST API for automation$q$, $q$Build custom scripts and integrations against Komga's full REST API.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('45a5beb8-a950-4bc0-908e-c7d7b3bef34a', $q$Metadata editing$q$, $q$View and edit series and book metadata including titles, publishers, genres, and reading order.$q$, 6);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('45a5beb8-a950-4bc0-908e-c7d7b3bef34a', $q$Docker-friendly self-hosted deployment$q$, $q$Run Komga on your own server or NAS hardware using official Docker images.$q$, 7);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('45a5beb8-a950-4bc0-908e-c7d7b3bef34a', $q$Completely free and open source with no subscription$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('45a5beb8-a950-4bc0-908e-c7d7b3bef34a', $q$Purpose-built for comics and manga, not a generic media server$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('45a5beb8-a950-4bc0-908e-c7d7b3bef34a', $q$Wide compatibility through OPDS and third-party reader apps like Mihon$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('45a5beb8-a950-4bc0-908e-c7d7b3bef34a', $q$Kobo Sync and KOReader Sync are rare, high-value features for e-reader owners$q$, 3);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('45a5beb8-a950-4bc0-908e-c7d7b3bef34a', $q$Active Discord community and regular updates$q$, 4);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('45a5beb8-a950-4bc0-908e-c7d7b3bef34a', $q$Requires self-hosting knowledge and server infrastructure$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('45a5beb8-a950-4bc0-908e-c7d7b3bef34a', $q$No official hosted cloud version$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('45a5beb8-a950-4bc0-908e-c7d7b3bef34a', $q$No built-in remote-access relay service like Plex offers$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('45a5beb8-a950-4bc0-908e-c7d7b3bef34a', $q$Smaller mainstream awareness compared to Plex or Jellyfin$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('45a5beb8-a950-4bc0-908e-c7d7b3bef34a', $q$Depends on a single lead maintainer for long-term project continuity$q$, 4);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('45a5beb8-a950-4bc0-908e-c7d7b3bef34a', $q$Is Komga free?$q$, $q$Yes, Komga is completely free and open-source software under the MIT license, with no subscription or paid tier.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('45a5beb8-a950-4bc0-908e-c7d7b3bef34a', $q$What file formats does Komga support?$q$, $q$Komga supports CBZ, CBR, PDF, and EPUB files for comics, manga, and eBooks.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('45a5beb8-a950-4bc0-908e-c7d7b3bef34a', $q$Can I read Komga on a Kobo e-reader?$q$, $q$Yes, Komga has native Kobo Sync support, letting Kobo e-readers pull books directly from your Komga server.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('45a5beb8-a950-4bc0-908e-c7d7b3bef34a', $q$Who created Komga?$q$, $q$Komga was created by developer Gauthier Roebroeck, with the project beginning in 2019.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('45a5beb8-a950-4bc0-908e-c7d7b3bef34a', $q$Does Komga have a mobile reading app?$q$, $q$Komga does not ship its own dedicated mobile app, but it works with third-party apps like Mihon on Android and any OPDS-compatible e-reader app.$q$, 4, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('45a5beb8-a950-4bc0-908e-c7d7b3bef34a', $q$How is Komga different from Kavita?$q$, $q$Komga and Kavita are both free, open-source, self-hosted comic and eBook servers with similar core features; they differ mainly in UI design and specific integrations like Komga's Kobo Sync support.$q$, 5, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('45a5beb8-a950-4bc0-908e-c7d7b3bef34a', $q$Personal comics and manga library$q$, $q$Readers with large digital comics or manga collections self-host Komga to browse and read from any device with a consistent, centralized library.$q$, $q$Comic and manga readers$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('45a5beb8-a950-4bc0-908e-c7d7b3bef34a', $q$Kobo and e-reader synchronization$q$, $q$Kobo e-reader owners connect their device directly to a Komga server to sync new comics and reading progress without manual file transfers.$q$, $q$Kobo and KOReader device owners$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('45a5beb8-a950-4bc0-908e-c7d7b3bef34a', $q$Family media server with content restrictions$q$, $q$Households set up multi-user access with age and content-label restrictions so a shared Komga library is safe for younger readers.$q$, $q$Families sharing a home media server$q$, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('45a5beb8-a950-4bc0-908e-c7d7b3bef34a', $q$Komga$q$, $q$Free$q$, $q$N/A$q$, NULL, $q$["Self-hosted comics and eBook media server","Support for CBZ, CBR, PDF, EPUB","OPDS, Kobo Sync, and KOReader Sync","REST API access","Multi-user permissions"]$q$::jsonb, 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('45a5beb8-a950-4bc0-908e-c7d7b3bef34a', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$Komga is a free, open-source, self-hosted media server built specifically for comics, manga, and eBooks, created by developer Gauthier Roebroeck with the project dating back to 2019 and released under the MIT license. Written in Kotlin and distributed as a Docker-friendly Java application, it runs entirely on infrastructure the user controls.$q$, $q$Komga ingests CBZ, CBR, PDF, and EPUB files and organizes them into libraries, collections, and reading lists, with metadata editing for series titles, publishers, genres, and reading order.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('45a5beb8-a950-4bc0-908e-c7d7b3bef34a', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$Access is provided through a built-in responsive web reader, OPDS and OPDS-PS syndication support for any compatible e-reader app, native Kobo Sync for direct Kobo device access, KOReader Sync for progress synchronization, and compatibility with third-party apps like Mihon on Android.$q$, $q$A full REST API underlies the server, enabling community automation tools, and multi-user access with age and content-label restrictions makes Komga practical for households sharing a single library.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('45a5beb8-a950-4bc0-908e-c7d7b3bef34a', $q$pricing-overview$q$, $q$Pricing$q$, 2, ARRAY[$q$Komga is completely free and open source with no subscription, licensing fee, or paid tier of any kind, funded informally through community donations rather than commercial revenue.$q$, $q$There is no official hosted cloud version; users self-host Komga on their own server, NAS, or home lab hardware, typically via Docker, and support is available through an active community Discord server.$q$]::text[], 2);
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('45a5beb8-a950-4bc0-908e-c7d7b3bef34a', '97eb8f3e-e378-4a5d-b2a5-331706e86e50') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('45a5beb8-a950-4bc0-908e-c7d7b3bef34a', 'efe7ced3-7cfa-4b39-9792-3427d24fa58d') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('45a5beb8-a950-4bc0-908e-c7d7b3bef34a', '4137e3dc-5b54-4d6a-adfa-85ce8104e38f') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('45a5beb8-a950-4bc0-908e-c7d7b3bef34a', '7336153f-a26b-491c-b927-faf4f5a8d103') ON CONFLICT DO NOTHING;
