-- ── Kodi ──────────────────────────────────────────────
UPDATE tools SET
  short_description = COALESCE($q$Kodi is a free, open-source media center application that organizes and plays local and network video, music, photos, and live TV across many devices.$q$, short_description),
  pricing_model = COALESCE($q$Free$q$, pricing_model),
  starting_price = COALESCE($q$Free$q$, starting_price),
  founded_year = COALESCE(2002, founded_year),
  company_size = COALESCE(NULL, company_size),
  headquarters = COALESCE(NULL, headquarters),
  languages = ARRAY[$q$English$q$]::text[],
  seo_title = COALESCE($q$Kodi Review 2026: Features, Pricing and Alternatives$q$, seo_title),
  seo_meta_description = COALESCE($q$Kodi is a free, open-source home theater software from the XBMC Foundation. See its features, supported platforms, and how it compares to Plex and Jellyfin.$q$, seo_meta_description),
  llm_readable_summary = COALESCE($q$Kodi is a free, open-source home theater and media center application with roots dating back to 2002, when it began as an independently developed homebrew media player for the original Xbox console called Xbox Media Player. After merging with a similar project called YAMP in November 2002, the software was renamed Xbox Media Center, abbreviated XBMC, and its first stable release, XboxMediaCenter 1.0.0, shipped on June 29, 2004. To manage growing development costs, paperwork, and conference travel, the community established the XBMC Foundation as a tax-exempt, registered non-profit organization in the United States on January 16, 2009, and this foundation remains the legal entity that owns and governs Kodi's code today. In July 2014, with the release of version 14, the project was rebranded from XBMC to Kodi, reflecting its expansion well beyond the original Xbox platform, while the XBMC Foundation name was retained for the legal entity. Kodi is developed entirely by a global community of unpaid volunteers, more than 500 software developers have contributed code and over 100 translators have helped localize the interface into more than 70 languages, and the source code is distributed under the GNU General Public License version 2 or later. Functionally, Kodi is a highly customizable, skinnable application that organizes and plays local and network media: movies, TV shows, music, photos, podcasts, and live TV or DVR content accessed through PVR add-ons. It supports an extremely wide range of video and audio codecs and container formats, scrapes rich metadata such as posters, fan art, cast information, and plot summaries for movies and TV libraries, and can sync a shared media library across multiple installations using a central MySQL or MariaDB database. Kodi's add-on repository system is central to its appeal, letting users install additional skins, video and audio plugins, PVR backends for live TV tuners, and other extensions to customize functionality well beyond the base application. It runs natively on Windows, macOS, Linux, Android, iOS, tvOS, and BSD, and is commonly deployed on dedicated home-theater PCs, Raspberry Pi boards, and set-top boxes, often via purpose-built Kodi-based Linux distributions such as LibreELEC and OSMC that turn low-cost hardware into a dedicated streaming appliance. Users can control playback through the on-device interface, a built-in web interface, or companion remote-control apps on phones and tablets. Because Kodi is entirely free and community-funded through donations to the XBMC Foundation, there is no subscription, license fee, or paid tier of any kind, and the project's continued existence does not depend on a commercial company remaining in business. Kodi's target audience is home theater PC enthusiasts, cord-cutters who want to organize and play their own media collections or watch live TV without a cable subscription, and DIY hobbyists who build custom streaming boxes on inexpensive hardware. Its main competitors and alternatives include Plex, a freemium, more consumer-polished media server that uses a client-server model with a central server streaming to multiple remote clients and offers paid premium features like remote access and live TV DVR; Jellyfin, a free and fully open-source Plex-style media server that, like Kodi, has no commercial company behind it and emphasizes privacy and community governance; and Emby, another freemium client-server media server comparable to Plex. Kodi differs from all three architecturally: rather than a client-server model with a central media server streaming to many remote devices, Kodi is traditionally installed and run directly on the playback device itself, though it can also browse and stream from network shares or, via add-ons, from an existing Plex or Jellyfin server, and it offers no official cloud relay service or commercial premium tier since the entire project remains volunteer-run and donation-funded.$q$, llm_readable_summary),
  status = 'published',
  noindex = false,
  sitemap_eligible = true,
  published_at = COALESCE(published_at, now()),
  updated_at = now()
WHERE id = 'f15ae2d8-b82f-4e7b-b033-07c65a5c2617';

