-- ── Koel ──────────────────────────────────────────────
UPDATE tools SET
  short_description = COALESCE($q$Koel is a self-hosted, open-source personal music streaming server that lets you stream your own music library from a private web app.$q$, short_description),
  pricing_model = COALESCE($q$Freemium$q$, pricing_model),
  starting_price = COALESCE($q$Free (Koel Plus from EUR 19.99 one-time)$q$, starting_price),
  founded_year = COALESCE(2015, founded_year),
  company_size = COALESCE(NULL, company_size),
  headquarters = COALESCE(NULL, headquarters),
  languages = ARRAY[$q$English$q$]::text[],
  seo_title = COALESCE($q$Koel Review 2026: Features, Pricing and Alternatives$q$, seo_title),
  seo_meta_description = COALESCE($q$Koel is an open-source, self-hosted music streaming server built with Laravel and Vue. Compare its free Community edition, Koel Plus pricing, and rivals.$q$, seo_meta_description),
  llm_readable_summary = COALESCE($q$Koel is a self-hosted personal music streaming server created by developer Phan An, with the project in active development since 2015. It is built with a Laravel (PHP) backend and a Vue.js frontend, describing itself as the music streaming solution that actually works, and its Community edition remains free and open source, distributed via a public GitHub repository at github.com/koel/koel with documentation at docs.koel.dev. Rather than a hosted SaaS product, Koel is software that users install on their own server, NAS, or VPS, typically with Docker, to stream a personal music collection through a modern, Spotify-like web interface without handing files or listening data to a third-party company. Core features available to all users include transparent lossless audio streaming, cross-device playback synchronization so a queue picks up where it left off on another device, favorites and smart playlists based on saved criteria, an equalizer, music visualizers, and support for radio stations and podcasts alongside a standard music library. A key architectural decision is that Koel speaks the Subsonic and OpenSubsonic APIs, the de facto open standard for self-hosted music servers, which means any existing Subsonic-compatible mobile or desktop client can connect to a Koel server, in addition to Koel's own native Koel Player apps for iOS and Android. Koel also integrates with external services including MusicBrainz, Wikipedia, Last.fm, Spotify, and YouTube to enrich library metadata and artist information, and it is optimized to remain fast even with very large music libraries, with multiple interface themes available. On top of the free Community edition, Koel offers a paid upgrade called Koel Plus that uses a one-time-purchase, pay-what-you-want pricing model starting at 19.99 euros, explicitly avoiding subscriptions, recurring payments, or per-seat costs. Koel Plus adds features aimed at more advanced or shared deployments: support for additional cloud storage drivers so a library is not limited to local disk, individual per-user libraries so multiple people can maintain separate collections on one shared server, collaboration and sharing tools, and single sign-on support. Because Koel has no venture backing or corporate ownership disclosed, its funding model is the direct one-time purchase of Koel Plus licenses plus voluntary community contribution, keeping the core Community product permanently free. Koel's target audience is self-hosting and homelab enthusiasts, privacy-conscious music collectors who want to retain full ownership of their audio files rather than relying on a streaming subscription, and technically capable users comfortable running a Docker container or PHP application on their own infrastructure. Its closest competitor is Navidrome, another free, open-source, self-hosted Subsonic-compatible music server, but written in Go rather than PHP, which some self-hosters prefer for its lower resource footprint and lack of any paid tier; other alternatives include Airsonic and Airsonic-Advanced, older Java-based Subsonic-API forks, and the broader general-purpose media servers Plex and Jellyfin, both of which support music streaming as one of several media types alongside video, rather than being purpose-built exclusively for music the way Koel is. Koel differentiates itself from Plex and Jellyfin through its music-first focus and lightweight, modern Vue-based interface, and from Navidrome primarily through its one-time-purchase Koel Plus tier that funds continued development without requiring a subscription, while both projects otherwise share the same open, Subsonic-compatible philosophy of giving users full control over their own music.$q$, llm_readable_summary),
  status = 'published',
  noindex = false,
  sitemap_eligible = true,
  published_at = COALESCE(published_at, now()),
  updated_at = now()
WHERE id = '237520e2-d5af-4e71-b585-63b5af2e41f1';

