-- ── Koha ──────────────────────────────────────────────
UPDATE tools SET
  short_description = COALESCE($q$Koha is a free, open-source integrated library system used by libraries worldwide to manage cataloging, circulation, patrons, and online public access catalogs.$q$, short_description),
  pricing_model = COALESCE($q$Open Source$q$, pricing_model),
  starting_price = COALESCE($q$Free (self-hosted); paid managed hosting varies by vendor$q$, starting_price),
  founded_year = COALESCE(1999, founded_year),
  company_size = COALESCE(NULL, company_size),
  headquarters = COALESCE(NULL, headquarters),
  languages = ARRAY[$q$English$q$]::text[],
  seo_title = COALESCE($q$Koha Review 2026: Features, Pricing and Alternatives$q$, seo_title),
  seo_meta_description = COALESCE($q$Koha is the world's first open-source library system, used by thousands of libraries worldwide. See its features, hosting costs, and how it compares to Evergreen.$q$, seo_meta_description),
  llm_readable_summary = COALESCE($q$Koha is a free, open-source integrated library system, or ILS, created in 1999 by Katipo Communications under contract for the Horowhenua Library Trust, a three-branch public library system in New Zealand that needed to replace a legacy system which was not compliant with the year 2000 date change. The first live installation went into production in January 2000, with Chris Cormack, then employed at Katipo, serving as lead developer and remaining an active contributor to the project for decades afterward. Once the system was completed, Katipo and the Horowhenua Library Trust made the decision to release the code as open source rather than keep it proprietary, and the project was named Koha, which means gift or donation in the Maori language of New Zealand's indigenous population, reflecting that choice. Koha is widely credited as the first open-source integrated library system in the world, and it is governed today by a global community of contributors under formal structures that include the Horowhenua Library Trust Koha Committee and a community Code of Conduct, with the code released under the GNU General Public License. As of recent counts, more than 4,700 libraries across over 6,600 individual facilities and branches in more than 100 countries run Koha, spanning public, academic, school, and special libraries, a scale of adoption that has led industry analysts to describe it as the most widely implemented open-source ILS in the world. Functionally, Koha is a fully featured, web-based system covering the core operational needs of a library: cataloging using the MARC21 and UNIMARC bibliographic standards, circulation management for checkouts, holds, and fines, acquisitions and serials management for ordering and tracking new materials and periodicals, patron and member account management, and a public-facing Online Public Access Catalog, or OPAC, that lets patrons search the collection, place holds, and manage their own accounts through a responsive interface that works across desktop and mobile devices. Because Koha carries no licensing fee and its source code is fully open, libraries have two practical paths to running it: self-hosting the software themselves on infrastructure running MySQL or MariaDB with a Perl-based application layer and a search index such as Zebra or Elasticsearch, which requires in-house technical staff, or contracting one of several independent commercial support companies, including firms such as ByWater Solutions, PTFS Europe, and BibLibre, for managed hosting, data migration, customization, and ongoing support. Because the Koha project itself does not sell hosting or support contracts, pricing for the managed-hosting path is set independently by each vendor and varies by library size and service level rather than being fixed centrally, meaning total cost of ownership for adopting libraries typically comes down to either staff time for self-hosting or a support contract fee paid to a chosen vendor. Development is sponsored collectively by libraries of varying types and sizes, individual volunteers, and these commercial support companies, with releases coordinated by elected release managers, community mailing lists and chat channels, and an annual KohaCon conference that brings the global community together. Koha's target users are public libraries, school libraries, academic and special libraries, and multi-branch library consortia, particularly smaller or budget-constrained institutions that want to avoid the recurring licensing costs of proprietary commercial ILS platforms while still getting enterprise-grade cataloging and circulation functionality comparable to paid alternatives. Its principal competitors are Evergreen, another prominent free and open-source ILS originally built for the Georgia Public Library Service and especially popular with large library consortia, and proprietary commercial systems such as Ex Libris Alma and Voyager, SirsiDynix Symphony, Follett Destiny, which is common in K-12 school libraries, and Innovative Interfaces' Polaris and Sierra platforms. Koha differentiates itself from Evergreen through its longer history dating back to 1999 versus Evergreen's 2006 origin, its broader overall global adoption footprint, and its larger ecosystem of competing commercial support vendors; compared with proprietary systems like SirsiDynix or Ex Libris, Koha's core differentiator is that adopting libraries own their data and code outright with zero licensing fees and can switch support vendors freely at any time, whereas proprietary ILS platforms lock a library into a single vendor's pricing structure and product roadmap.$q$, llm_readable_summary),
  status = 'published',
  noindex = false,
  sitemap_eligible = true,
  published_at = COALESCE(published_at, now()),
  updated_at = now()
WHERE id = '6642f7be-b54a-4974-8b1c-50cd8c2c2785';

