-- ── Komga ──────────────────────────────────────────────
UPDATE tools SET
  short_description = COALESCE($q$Komga is a free, open-source, self-hosted media server for organizing and reading comics, manga, magazines, and eBooks from any device.$q$, short_description),
  pricing_model = COALESCE($q$Free$q$, pricing_model),
  starting_price = COALESCE($q$Free$q$, starting_price),
  founded_year = COALESCE(2019, founded_year),
  company_size = COALESCE(NULL, company_size),
  headquarters = COALESCE(NULL, headquarters),
  languages = ARRAY[$q$English$q$]::text[],
  seo_title = COALESCE($q$Komga Review 2026: Features, Pricing and Alternatives$q$, seo_title),
  seo_meta_description = COALESCE($q$Komga is a free, open-source, self-hosted comics and manga server with OPDS and Kobo Sync support. See its features and how it compares to Kavita and Plex.$q$, seo_meta_description),
  llm_readable_summary = COALESCE($q$Komga is a free, open-source, self-hosted media server built specifically for comics, manga, French-language BDs (bandes dessinees), magazines, and eBooks, created by developer Gauthier Roebroeck, known on GitHub as gotson, with the project's public repository dating back to 2019. Written in Kotlin and distributed under the MIT license, Komga is packaged as a Docker-friendly Java application that users run on their own server, NAS, or home lab hardware rather than through any hosted cloud service. The server ingests files in CBZ, CBR, PDF, and EPUB formats and organizes them into libraries, collections, and reading lists, while allowing users to view and edit metadata such as series titles, publishers, genres, age ratings, and reading order directly within the app. Access is provided through several complementary channels: a responsive, built-in web reader that works across desktop, tablet, and phone browsers without installing anything; compatibility with the OPDS and OPDS-PS (Page Streaming) syndication protocols, which lets any OPDS-compatible e-reader or reading app browse and download from a Komga library; native Kobo Sync support, which lets Kobo e-readers pull new books directly from a Komga server without manual file transfers; KOReader Sync, which keeps reading progress synchronized with the popular KOReader app; and compatibility with popular third-party reading apps such as Mihon (the actively maintained successor to Tachiyomi) on Android. A full REST API underlies the entire server, which has enabled a community ecosystem of companion scripts and tools for automation, metadata scraping, and library management beyond what ships in the core application. Komga supports multi-user access with per-library permission controls, including age-restriction and content-label settings, which makes it practical for households sharing one server while limiting what younger users can browse or read. There is no company or commercial entity behind Komga: it is maintained by its creator together with community contributors, and the project accepts informal donations rather than charging any subscription fee, meaning there is no paid tier, hosted SaaS version, or licensing cost of any kind. Project documentation is published through a Docusaurus-based site at komga.org, and an active Discord server serves as the primary hub for user support, feature requests, and community discussion. Komga's target users are comic and manga readers with substantial digital collections, digital library managers, and self-hosting hobbyists who want a centralized, cross-device reading experience comparable to what commercial digital comics services have historically offered, but running entirely under their own control and without a recurring subscription. Its closest direct competitor is Kavita, another free, open-source, self-hosted comics and eBook server with a broadly similar feature set, including a web reader, OPDS support, and metadata management, and the choice between the two often comes down to interface preference and specific integrations, since both are actively maintained MIT-licensed community projects with comparable scope. Other adjacent alternatives include Ubooquity, an older and simpler self-hosted comic and eBook server; Calibre-Web, a self-hosted web interface built around the Calibre eBook library manager that is more eBook-focused than comics-focused; and the general-purpose media servers Plex and Jellyfin, both of which have added or support comic-reading capabilities through plugins or agents but were not purpose-built for sequential-art formats the way Komga was from the outset. Komga differentiates itself through comics-specific features that few competitors match, particularly its native Kobo Sync and KOReader Sync integrations, its full OPDS compliance for broad e-reader app compatibility, and its lightweight, Docker-first deployment model that targets self-hosters specifically rather than the broader mainstream consumer audience that Plex and Jellyfin also serve with their all-purpose media libraries.$q$, llm_readable_summary),
  status = 'published',
  noindex = false,
  sitemap_eligible = true,
  published_at = COALESCE(published_at, now()),
  updated_at = now()
WHERE id = '45a5beb8-a950-4bc0-908e-c7d7b3bef34a';

